//! Sample WASM modules for testing
//!
//! Binary fixtures representing valid and invalid WASM modules

// Minimal valid WASM module (wat format compiled to binary)
// This is a simple module that exports a function
pub const VALID_WASM_MODULE: &[u8] = &[
    0x00, 0x61, 0x73, 0x6d, // Magic: \0asm
    0x01, 0x00, 0x00, 0x00, // Version: 1
    // Type section
    0x01, 0x07, 0x01, 0x60, 0x02, 0x7f, 0x7f, 0x01, 0x7f,
    // Function section
    0x03, 0x02, 0x01, 0x00,
    // Export section
    0x07, 0x0b, 0x01, 0x06, 0x61, 0x64, 0x64, 0x4e, 0x75, 0x6d, 0x00, 0x00,
    // Code section
    0x0a, 0x09, 0x01, 0x07, 0x00, 0x20, 0x00, 0x20, 0x01, 0x6a, 0x0b,
];

