#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_wasm_module_validity() {
        // Check magic number
        assert_eq!(&VALID_WASM_MODULE[0..4], &[0x00, 0x61, 0x73, 0x6d]);
        assert_eq!(&VALID_WASM_MODULE[4..8], &[0x01, 0x00, 0x00, 0x00]);
    }

    #[test]
    fn test_key_lengths() {
        assert_eq!(TEST_PUBLIC_KEY.len(), 32);
        assert_eq!(TEST_SECRET_KEY.len(), 64);
        assert_eq!(TEST_SIGNATURE.len(), 64);
    }
}
